  ('social-worker-moex-03287', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '低社經地位對於個人發展影響深遠，許多研究也都發現社經地位與兒童發展密切相關，低社經地 位對兒童造成的影響，下列何者錯誤？', '["生活在貧困中且住屋擁擠，對5歲以下兒童的大腦發展有不良影響", "生活在貧困和壓力中，導致兒童學習、注意力、記憶力不佳問題", "經濟弱勢與精神疾病存在著因果關係", "低社經地位群體兒童比高社經地位群體兒童更容易有疾病感染問題"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03288', 'social-worker', 'social-worker-moex-114-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '「養育一個孩子需要整體社區的協力」意味著「認同有幼童的家庭需要支持，而社會的價值觀也 認同這樣的支持」，這樣的社區成員經常是具有共同的價值觀和信任的協力網絡。這樣的敘述最符 合下列那項概念？', '["人力資本", "人際關係", "社會資本", "社區投資"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:17+00:00", "source_pdf_sha1": "a087d56213ab", "answer_pdf_sha1": "daeec4fbf76e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "103", "s": "0305", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
